// $input.first().json IS the already-parsed Ollama JSON response
const resp = $input.first().json;
const specText = (resp.message?.content || resp.response || '').trim();
if (!specText) throw new Error('Ollama returned empty response');

const buildData = $('Build Prompt').first().json;
const channelId = buildData.channelId || '';
const description = buildData.description || '';

return [{ json: { specText, channelId, description } }];

const https = require('https');

function httpsReq(options, body) {
  return new Promise((resolve, reject) => {
    if (Buffer.isBuffer(body)) {
      options.headers = options.headers || {};
      options.headers['Content-Length'] = body.length;
    }
    const req = https.request(options, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(text)); } catch { resolve({ _raw: text }); }
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const token = $env.SLACK_BOT_TOKEN;
const item = $input.first().json;
const specText = item.specText || '';
const channelId = item.channelId || '';
const description = item.description || '';

// Convert spec text to binary
const buf = Buffer.from(specText, 'utf8');
const slug = description.toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 40);
const fileName = `patent-spec-${slug}.txt`;

// Step 1: Get upload URL
const body1 = `filename=${encodeURIComponent(fileName)}&length=${buf.length}`;
const urlData = await httpsReq({
  method: 'POST', hostname: 'slack.com',
  path: '/api/files.getUploadURLExternal',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/x-www-form-urlencoded',
    'Content-Length': Buffer.byteLength(body1),
  }
}, Buffer.from(body1));

if (!urlData.ok) throw new Error(`getUploadURL failed: ${JSON.stringify(urlData)}`);
const { upload_url, file_id } = urlData;

// Step 2: PUT text content to upload URL
const urlMatch = upload_url.match(/^https?:\/\/([^\/]+)(\/[^?]*)?(\?.*)?$/);
await httpsReq({
  method: 'PUT', hostname: urlMatch[1],
  path: (urlMatch[2] || '/') + (urlMatch[3] || ''),
  headers: { 'Content-Type': 'text/plain; charset=utf-8', 'Content-Length': buf.length }
}, buf);

// Step 3: Complete — share directly to channel with context as initial_comment
// Count approximate word + page stats
const wordCount = specText.split(/\s+/).filter(Boolean).length;
const pageEstimate = Math.ceil(wordCount / 250);

const comment = [
  `:page_with_curl: *Patent Application Specification Draft*`,
  `*Invention:* ${description}`,
  ``,
  `_${wordCount.toLocaleString()} words · ~${pageEstimate} pages · Full text in attached file_`,
  `_Sections: Title · Field · Background · Summary · Drawings · Embodiments · Claims · Abstract_`,
  ``,
  `:warning: _AI-generated draft. Have a licensed US patent attorney review before filing._`,
].join('\n');

const completeBody = JSON.stringify({
  files: [{ id: file_id }],
  ...(channelId ? { channel_id: channelId } : {}),
  initial_comment: comment,
});

const completeResp = await httpsReq({
  method: 'POST', hostname: 'slack.com',
  path: '/api/files.completeUploadExternal',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(completeBody),
  }
}, Buffer.from(completeBody));

if (!completeResp.ok) throw new Error(`completeUpload failed: ${JSON.stringify(completeResp)}`);

return [{ json: { fileId: file_id, channelId, description, wordCount, uploaded: true } }];
